sql:
SELECT SUM(total_duration) as total_duration 
FROM episodes 
WHERE season_id = (SELECT season_id FROM seasons WHERE show_id = 1 AND season_num = 1);

SELECT user_id, SUM(viewed_duration) AS total_viewing_time
FROM viewing_history
WHERE user_id = 1;

SELECT SUM(episodes) 
FROM seasons 
WHERE show_id = (SELECT show_id FROM shows WHERE show_name = 'Game of Thrones');

SELECT user_id, COUNT(episode_id) AS NumberOfEpisodesWatched
FROM viewing_history
GROUP BY user_id;

SELECT AVG(viewed_duration) AS average_duration
FROM viewing_history
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Jane Smith') AND viewed_duration > 0;

SELECT vh.episode_id, u.user_name, vh.buffering_time
FROM viewing_history vh
JOIN users u ON vh.user_id = u.user_id
WHERE vh.user_id = 1 AND vh.buffering_time = (
    SELECT MAX(buffering_time) FROM viewing_history WHERE user_id = 1
);

SELECT u.user_name, u.role
FROM users u
WHERE u.is_active = 1 AND u.user_id NOT IN (SELECT w.user_id FROM watchlists w);
